import SwiftUI
import ARKit
import RealityKit
import UIKit

struct ARViewContainer: UIViewRepresentable {
    typealias UIViewType = ARView
    @Binding var measurementText: String

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    func makeUIView(context: Context) -> ARView {
        let arView = ARView(frame: .zero)
        let config = ARWorldTrackingConfiguration()
        config.planeDetection = [.horizontal, .vertical]
        arView.session.run(config)
        arView.session.delegate = context.coordinator

        let tapGesture = UITapGestureRecognizer(
            target: context.coordinator,
            action: #selector(Coordinator.handleTap(_:))
        )
        arView.addGestureRecognizer(tapGesture)

        return arView
    }

    func updateUIView(_ uiView: ARView, context: Context) {}

    class Coordinator: NSObject, ARSessionDelegate {
        var parent: ARViewContainer
        var points: [simd_float4x4] = []

        init(_ parent: ARViewContainer) {
            self.parent = parent
        }

        @objc func handleTap(_ recognizer: UITapGestureRecognizer) {
            guard let arView = recognizer.view as? ARView else { return }
            let location = recognizer.location(in: arView)
            let results = arView.raycast(from: location, allowing: .estimatedPlane, alignment: .any)
            guard let result = results.first else { return }

            let sphere = ModelEntity(
                mesh: .generateSphere(radius: 0.005),
                materials: [SimpleMaterial(color: .systemBlue, isMetallic: false)]
            )
            let anchor = AnchorEntity(world: result.worldTransform)
            anchor.addChild(sphere)
            arView.scene.addAnchor(anchor)

            points.append(result.worldTransform)
            if points.count == 2 {
                let distance = simd_distance(points[0].columns.3, points[1].columns.3)
                let cm = distance * 100
                parent.measurementText = String(format: "%.1f cm", cm)
                points.removeAll()
            }
        }
    }
}

