import SwiftUI
import Combine

class TaskViewModel: ObservableObject {
    @Published var tasks: [Task] = [
        Task(title: "Design the onboarding flow"),
        Task(title: "Review pull requests"),
        Task(title: "Write unit tests", isCompleted: true),
        Task(title: "Update documentation"),
        Task(title: "Fix navigation bug", isCompleted: true)
    ]
    @Published var newTaskTitle: String = ""
    @Published var selectedFilter: FilterOption = .all

    enum FilterOption: String, CaseIterable, Identifiable {
        case all = "All"
        case active = "Active"
        case completed = "Completed"

        var id: String { rawValue }
    }

    var filteredTasks: [Task] {
        switch selectedFilter {
        case .all:
            return tasks
        case .active:
            return tasks.filter { !$0.isCompleted }
        case .completed:
            return tasks.filter { $0.isCompleted }
        }
    }

    var completedCount: Int {
        tasks.filter { $0.isCompleted }.count
    }

    var totalCount: Int {
        tasks.count
    }

    func addTask() {
        let trimmed = newTaskTitle.trimmingCharacters(in: .whitespaces)
        guard !trimmed.isEmpty else { return }
        withAnimation(.spring(response: 0.35, dampingFraction: 0.85)) {
            tasks.insert(Task(title: trimmed), at: 0)
        }
        newTaskTitle = ""
    }

    func toggleTask(_ task: Task) {
        if let index = tasks.firstIndex(where: { $0.id == task.id }) {
            withAnimation(.spring(response: 0.3, dampingFraction: 0.8)) {
                tasks[index].isCompleted.toggle()
            }
        }
    }

    func clearCompleted() {
        withAnimation(.spring(response: 0.35, dampingFraction: 0.85)) {
            tasks.removeAll { $0.isCompleted }
        }
    }

    func deleteTask(at offsets: IndexSet) {
        let filtered = filteredTasks
        let idsToDelete = offsets.map { filtered[$0].id }
        withAnimation(.spring(response: 0.35, dampingFraction: 0.85)) {
            tasks.removeAll { idsToDelete.contains($0.id) }
        }
    }
}

